BEGIN;
CREATE TABLE market.feed_providers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider_key text UNIQUE NOT NULL, name text NOT NULL, provider_type text NOT NULL, status text NOT NULL, enabled boolean NOT NULL DEFAULT true, config jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE market.feed_health (observed_at timestamptz NOT NULL DEFAULT now(), id uuid NOT NULL DEFAULT gen_random_uuid(), provider_id uuid NOT NULL REFERENCES market.feed_providers(id) ON DELETE CASCADE, status text NOT NULL, latency_ms integer, tick_rate integer, quality_score numeric(7,4), PRIMARY KEY(observed_at,id));
SELECT create_hypertable('market.feed_health', by_range('observed_at'), if_not_exists => TRUE);
CREATE TABLE market.feed_latency (observed_at timestamptz NOT NULL DEFAULT now(), id uuid NOT NULL DEFAULT gen_random_uuid(), provider_id uuid NOT NULL REFERENCES market.feed_providers(id) ON DELETE CASCADE, latency_ms integer NOT NULL, packet_loss numeric(7,4) NOT NULL DEFAULT 0, PRIMARY KEY(observed_at,id));
CREATE TABLE market.feed_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider_id uuid REFERENCES market.feed_providers(id) ON DELETE CASCADE, event_type text NOT NULL, severity text NOT NULL, impact text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE market.feed_quality (observed_at timestamptz NOT NULL DEFAULT now(), id uuid NOT NULL DEFAULT gen_random_uuid(), provider_id uuid REFERENCES market.feed_providers(id) ON DELETE CASCADE, quality_score numeric(7,4) NOT NULL, freshness numeric(7,4), completeness numeric(7,4), consistency numeric(7,4), reliability numeric(7,4), PRIMARY KEY(observed_at,id));
CREATE TABLE market.feed_coverage (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider_id uuid NOT NULL REFERENCES market.feed_providers(id) ON DELETE CASCADE, symbol text NOT NULL, price_feed boolean NOT NULL, tick_feed boolean NOT NULL, volume_feed boolean NOT NULL, spread_feed boolean NOT NULL, status text NOT NULL, coverage numeric(7,4) NOT NULL, UNIQUE(provider_id,symbol));
CREATE TABLE market.feed_statistics (observed_at timestamptz NOT NULL DEFAULT now(), id uuid NOT NULL DEFAULT gen_random_uuid(), provider_id uuid NOT NULL REFERENCES market.feed_providers(id) ON DELETE CASCADE, tick_rate integer, dropped_packets integer NOT NULL DEFAULT 0, reconnects integer NOT NULL DEFAULT 0, PRIMARY KEY(observed_at,id));
COMMIT;
